// ── Public API ────────────────────────────────
function pickN<T>(arr: T[], n: number): T[] {
  return [...arr].sort(() => Math.random() - 0.5).slice(0, Math.min(n, arr.length));
}

export function getLessonBank(title: string): TieredBank {
  return B[title] ?? FALLBACK;
}

const TIER_KEYS = ["t0", "t1", "t2", "t3"] as const;

/**
 * يرجّع كل أسئلة المحطة (من المستويات الأربعة) بترتيب ثابت غير عشوائي،
 * مرتّبة حسب id. يُستخدم لتوزيع الأسئلة على الدروس الأربعة بدون تكرار.
 */
export function getAllStationExercises(title: string): ExObj[] {
  const bank = getLessonBank(title);
  const all: ExObj[] = [];
  const seen = new Set<string>();
  for (const key of TIER_KEYS) {
    for (const ex of bank[key] ?? []) {
      if (!seen.has(ex.id)) { all.push(ex); seen.add(ex.id); }
    }
  }
  // ترتيب ثابت حسب id (غير عشوائي) لضمان توزيع متّسق
  return all.sort((a, b) => a.id.localeCompare(b.id));
}

/**
 * اختبار القسم الشامل — يجمع أهم الأسئلة من كل وحدات القسم الأول.
 * سؤالان من كل وحدة (متوسط/صعب) = اختبار حقيقي يثبت فهم كل القسم.
 */
const SECTION1_STATIONS: string[] = [
  "الكلمات الأساسية", "جمل كاملة",        // و1 مشروبات
  "ما اسمك؟", "عائلتك",                    // و2 تعريف
  "الصفات الأساسية", "قارن بين الأشياء",   // و3 صفات
  "أماكن في المدينة", "الاتجاهات",          // و4 أماكن
  "أسماء الأطعمة", "في المطعم",            // و5 طعام
  "في المطار", "في الطائرة",               // و6 مطار
  "أفعال المهن", "جمل المضارع",            // و7 مهن
  "أفعال يومية", "روتينك اليومي",          // و8 مضارع
  "كلمات الطقس", "صف الطقس",               // و9 طقس
  "أسماء الحيوانات", "صف حيوانك",          // و10 حيوانات
];

export function getSectionTestExercises(): ExObj[] {
  const test: ExObj[] = [];
  const seen = new Set<string>();
  const isUsable = (e: ExObj) =>
    (e.type === "translate" || e.type === "fill_blank") &&
    Array.isArray((e as any).options ?? (e as any).blankOptions) &&
    ((e as any).options ?? (e as any).blankOptions).length >= 2 &&
    !!e.correctAnswer;

  // سؤال واحد من كل محطة (تغطية شاملة للقسم)
  for (const title of SECTION1_STATIONS) {
    const usable = getAllStationExercises(title).filter(isUsable);
    if (usable.length === 0) continue;
    const pick = usable[Math.floor(Math.random() * usable.length)];
    if (pick && !seen.has(pick.id)) { test.push(pick); seen.add(pick.id); }
  }
  return test.sort(() => Math.random() - 0.5);
}

/**
 * Returns `count` exercises drawn from the requested tier ONLY, so every star
 * attempt (and the challenge test) is completely different and difficulty rises
 * with the tier. Properly authored tiers have >= count items; the adjacent-tier
 * top-up is only a safety net for short/fallback banks (de-duped by id).
 */
export function getLessonMiniExercises(
  lessonTitle: string,
  count: number,
  tier: 0 | 1 | 2 | 3
): ExObj[] {
  const bank = getLessonBank(lessonTitle);
  const pool = bank[TIER_KEYS[tier]] ?? [];

  // اضمن ظهور الأنماط الخاصة (اتبع النمط + الأزواج) إن وُجدت
  const special = pool.filter(e => e.type === "fill_blank" || e.type === "matching");
  const normal  = pool.filter(e => e.type !== "fill_blank" && e.type !== "matching");

  const chosen: ExObj[] = [];
  // خذ نمط واحد على الأقل من كل نوع خاص إن وجد
  const pickedSpecial = pickN(special, Math.min(2, special.length));
  chosen.push(...pickedSpecial);
  // أكمل الباقي من العادية
  chosen.push(...pickN(normal, count - chosen.length));

  // إذا ما زلنا أقل من العدد، خذ من الـ tiers المجاورة
  if (chosen.length < count) {
    const seen = new Set(chosen.map((e) => e.id));
    const order: (0 | 1 | 2 | 3)[] = [];
    for (let d = 1; d < 4; d++) {
      if (tier - d >= 0) order.push((tier - d) as 0 | 1 | 2 | 3);
      if (tier + d <= 3) order.push((tier + d) as 0 | 1 | 2 | 3);
    }
    for (const t of order) {
      if (chosen.length >= count) break;
      for (const e of pickN(bank[TIER_KEYS[t]], count)) {
        if (chosen.length >= count) break;
        if (!seen.has(e.id)) { chosen.push(e); seen.add(e.id); }
      }
    }
  }

  return chosen.sort(() => Math.random() - 0.5);
}

