B["Modal Verbs: Can & Must"] = {
  t0: [
    { id:"mv-t0-1", type:"translate", arabic:"أستطيع السباحة لكن لا أستطيع ركوب الدراجة", options:["I can swim but I cannot ride a bike","I can swim but I can't to ride a bike","I am able swim but I cannot ride a bike","I can swim but I must not ride a bike"], correctAnswer:"I can swim but I cannot ride a bike", explanation:"can = يستطيع، cannot = لا يستطيع — بدون to", xp:11 },
    { id:"mv-t0-2", type:"word_order", sentence:"You must wear a seatbelt in the car", correctAnswer:"You must wear a seatbelt in the car", explanation:"must + فعل مجرد — إلزام", xp:11 },
    { id:"mv-t0-3", type:"listen_select", listenSentence:"Can you help me with this box please", options:["Can","Must","Should","Will"], correctAnswer:"Can", explanation:"Can you...? — طلب مساعدة", xp:11 },
    { id:"mv-t0-4", type:"translate", arabic:"يجب أن تصل في الوقت المحدد", options:["You must arrive on time","You can arrive on time","You must to arrive on time","You must arriving on time"], correctAnswer:"You must arrive on time", explanation:"must + فعل مجرد (بدون to)", xp:11 },
    { id:"mv-t0-5", type:"picture_match", word:"can", pictureOptions:[{emoji:"💪",label:"can"},{emoji:"🚫",label:"cannot"},{emoji:"⚠️",label:"must"},{emoji:"❓",label:"might"}], correctAnswer:"can", explanation:"can = يستطيع 💪", xp:11 },
    { id:"mv-t0-6", type:"word_order", sentence:"She can speak three languages fluently", correctAnswer:"She can speak three languages fluently", explanation:"can + فعل مجرد — قدرة", xp:11 },
    { id:"mv-t0-7", type:"translate", arabic:"لا يجوز التدخين هنا", options:["You must not smoke here","You cannot smoke here","You should not smoke here","You may not smoke here"], correctAnswer:"You must not smoke here", explanation:"must not = حظر مطلق", xp:12 },
    { id:"mv-t0-8", type:"listen_select", listenSentence:"I must finish this report before I leave the office", options:["must","can","should","will"], correctAnswer:"must", explanation:"must = يجب — التزام شخصي قوي", xp:11 },
    { id:"mv-t0-9", type:"translate", arabic:"هل تستطيع أن تشرح ذلك مرة أخرى؟", options:["Can you explain that again?","Must you explain that again?","Do you can explain that again?","Can you to explain that again?"], correctAnswer:"Can you explain that again?", explanation:"Can you...? — طلب مهذب بدون to", xp:11 },
    { id:"mv-t0-10", type:"word_order", sentence:"We must not forget to lock the door", correctAnswer:"We must not forget to lock the door", explanation:"must not = لا ينبغي إطلاقاً (نهي)", xp:11 },
  ],
  t1: [
    { id:"mv-t1-1", type:"translate", arabic:"كان باستطاعتي العزف على البيانو وأنا صغير", options:["I could play the piano when I was young","I can play the piano when I was young","I was able to play the piano when I was young","Both A and C are correct"], correctAnswer:"Both A and C are correct", explanation:"could / was able to — كلاهما صح للقدرة في الماضي", xp:14 },
    { id:"mv-t1-2", type:"word_order", sentence:"You must have been exhausted after that long journey", correctAnswer:"You must have been exhausted after that long journey", explanation:"must have + تصريف ثالث — استنتاج قوي عن الماضي", xp:14 },
    { id:"mv-t1-3", type:"listen_select", listenSentence:"She cannot have finished the exam so quickly it was very hard", options:["cannot have","must have","could have","should have"], correctAnswer:"cannot have", explanation:"cannot have + تصريف ثالث — استحالة في الماضي", xp:14 },
    { id:"mv-t1-4", type:"translate", arabic:"يجب أن تكون قد نسيت موعدنا", options:["You must have forgotten our appointment","You must forgot our appointment","You must have forget our appointment","You had to forget our appointment"], correctAnswer:"You must have forgotten our appointment", explanation:"must have forgotten = لا بد أنك نسيت — استنتاج ماضٍ", xp:15 },
    { id:"mv-t1-5", type:"word_order", sentence:"Could you possibly move your car it is blocking the entrance", correctAnswer:"Could you possibly move your car it is blocking the entrance", explanation:"Could you possibly...? — طلب مهذب جداً", xp:14 },
    { id:"mv-t1-6", type:"translate", arabic:"لا داعي للمجيء مبكراً — الحفل يبدأ في التاسعة", options:["You don't have to come early — the party starts at nine","You must not come early — the party starts at nine","You cannot come early — the party starts at nine","You needn't to come early — the party starts at nine"], correctAnswer:"You don't have to come early — the party starts at nine", explanation:"don't have to = ليس ضرورياً (بخلاف must not = حظر)", xp:14 },
    { id:"mv-t1-7", type:"listen_select", listenSentence:"He was able to escape despite being surrounded", options:["was able to","could","managed to","Both A and C"], correctAnswer:"Both A and C", explanation:"was able to / managed to — إنجاز ناجح في الماضي", xp:14 },
    { id:"mv-t1-8", type:"translate", arabic:"يجب أن تتذكر أنك مسؤول عن قراراتك", options:["You must remember that you are responsible for your decisions","You can remember that you are responsible for your decisions","You must to remember that you are responsible for your decisions","You must remember that you responsible for your decisions"], correctAnswer:"You must remember that you are responsible for your decisions", explanation:"must + مجرد — تذكير بالتزام أخلاقي", xp:15 },
    { id:"mv-t1-9", type:"word_order", sentence:"Can this really be the same person I met five years ago", correctAnswer:"Can this really be the same person I met five years ago", explanation:"Can this be...? — دهشة واستفسار", xp:14 },
    { id:"mv-t1-10", type:"translate", arabic:"لم يكن بإمكانه القدوم حتى لو أراد", options:["He couldn't have come even if he had wanted to","He couldn't come even if he wanted to","He wasn't able to come even if he had wanted to","He couldn't have come even if he wanted to"], correctAnswer:"He couldn't have come even if he had wanted to", explanation:"couldn't have + تصريف ثالث — شرط ثالث", xp:15 },
  ],
  t2: [
    { id:"mv-t2-1", type:"translate", arabic:"كان ينبغي له التشاور مع المختصين قبل اتخاذ القرار", options:["He should have consulted specialists before making the decision","He should consult specialists before making the decision","He must have consulted specialists before making the decision","He ought to consulted specialists before making the decision"], correctAnswer:"He should have consulted specialists before making the decision", explanation:"should have + تصريف ثالث — نقد قرار ماضٍ", xp:17 },
    { id:"mv-t2-2", type:"word_order", sentence:"The results cannot be correct there must be an error in the calculations", correctAnswer:"The results cannot be correct there must be an error in the calculations", explanation:"cannot be = مستحيل، must be = لا بد — استنتاج منطقي", xp:18 },
    { id:"mv-t2-3", type:"listen_select", listenSentence:"You could have informed us earlier we would have prepared accordingly", options:["could have","should have","must have","might have"], correctAnswer:"could have", explanation:"could have = كان بإمكانك — إمكانية ضائعة", xp:17 },
    { id:"mv-t2-4", type:"translate", arabic:"لا يمكن للمدير أن يكون قد اطلع على هذه الوثائق — فهي سرية للغاية", options:["The manager cannot have seen these documents — they are highly confidential","The manager must not have seen these documents — they are highly confidential","The manager could not see these documents — they are highly confidential","The manager was not able to have seen these documents"], correctAnswer:"The manager cannot have seen these documents — they are highly confidential", explanation:"cannot have + تصريف ثالث = استحالة في الماضي", xp:18 },
    { id:"mv-t2-5", type:"word_order", sentence:"Candidates must have submitted their applications by the closing date to be considered", correctAnswer:"Candidates must have submitted their applications by the closing date to be considered", explanation:"must have submitted — شرط لازم للتأهل", xp:17 },
    { id:"mv-t2-6", type:"translate", arabic:"يمكن تفسير هذه البيانات بأكثر من طريقة", options:["This data can be interpreted in more than one way","This data could be interpreted in more than one way","This data must be interpreted in more than one way","This data may be interpreted in more than one way"], correctAnswer:"This data can be interpreted in more than one way", explanation:"can be interpreted = يمكن تفسيره — إمكانية عامة", xp:17 },
    { id:"mv-t2-7", type:"listen_select", listenSentence:"The proposal may well have merits but it must be evaluated more rigorously", options:["must be","should be","can be","ought to be"], correctAnswer:"must be", explanation:"must be evaluated = يجب أن يُقيَّم — إلزام أكاديمي", xp:17 },
    { id:"mv-t2-8", type:"translate", arabic:"لو كانوا يدركون الأمر لما كان بمقدورهم التقاعس", options:["Had they known they could not have stood idle","Had they known they could not stand idle","If they knew they couldn't have stood idle","Had they known they must not have stood idle"], correctAnswer:"Had they known they could not have stood idle", explanation:"Had they known — شرط ثالث، could not have stood = ما كان يمكنهم", xp:18 },
    { id:"mv-t2-9", type:"word_order", sentence:"The CEO must have been under enormous pressure to make such a drastic decision", correctAnswer:"The CEO must have been under enormous pressure to make such a drastic decision", explanation:"must have been = لا بد أنه كان — استنتاج قوي عن ماضٍ", xp:17 },
    { id:"mv-t2-10", type:"translate", arabic:"يمكن المجادلة بأن السياسة الحالية تتعارض مع الإطار القانوني القائم", options:["It can be argued that the current policy contradicts the existing legal framework","It could be argued that the current policy contradicts the existing legal framework","It must be argued that the current policy contradicts the existing legal framework","It can argue that the current policy contradicts the existing legal framework"], correctAnswer:"It can be argued that the current policy contradicts the existing legal framework", explanation:"It can be argued that = يمكن القول إن", xp:18 },
  ],
  t3: [
    { id:"mv-t3-1", type:"translate", arabic:"لا يمكن المبالغة في تقدير الدور الذي يمكن أن تؤديه التعليم في الحد من الفقر", options:["The role that education can play in alleviating poverty cannot be overstated","The role that education can play in alleviating poverty must not be overstated","The role that education must play in alleviating poverty cannot be overstated","The role education can play in alleviating poverty can not be overstated"], correctAnswer:"The role that education can play in alleviating poverty cannot be overstated", explanation:"cannot be overstated = لا يمكن المبالغة في تقديره", xp:23 },
    { id:"mv-t3-2", type:"word_order", sentence:"Policymakers must be seen to act decisively if public trust is to be restored", correctAnswer:"Policymakers must be seen to act decisively if public trust is to be restored", explanation:"must be seen to = يجب أن يُرى وكأنه يتصرف بحسم", xp:24 },
    { id:"mv-t3-3", type:"listen_select", listenSentence:"What could possibly have motivated such a reckless course of action", options:["could have","must have","should have","would have"], correctAnswer:"could have", explanation:"What could have motivated? = ما الذي كان يمكن أن يدفع إلى", xp:23 },
    { id:"mv-t3-4", type:"translate", arabic:"أياً كانت العواقب فلا يمكن التسامح مع انتهاك هذه المبادئ", options:["Whatever the consequences these principles must not be compromised","Whatever the consequences these principles cannot be compromised","Whatever the consequences these principles should not be compromised","Whatever the consequences these principles must not compromise"], correctAnswer:"Whatever the consequences these principles must not be compromised", explanation:"must not be compromised = لا يجوز المساس بها — نهي مطلق مبني للمجهول", xp:24 },
    { id:"mv-t3-5", type:"word_order", sentence:"The fact that no objections were raised cannot have gone unnoticed by the committee", correctAnswer:"The fact that no objections were raised cannot have gone unnoticed by the committee", explanation:"cannot have gone unnoticed = لا يمكن أن يكون قد مرّ مرور الكرام", xp:25 },
    { id:"mv-t3-6", type:"translate", arabic:"يجب ألا تُتخذ قرارات مصيرية في ظل ظروف تفتقر إلى الشفافية", options:["Far-reaching decisions must not be taken under conditions that lack transparency","Far-reaching decisions must not be made under conditions lacking in transparency","Far-reaching decisions cannot be made under conditions lacking in transparency","Far-reaching decisions should not be made under conditions lacking transparency"], correctAnswer:"Far-reaching decisions must not be taken under conditions that lack transparency", explanation:"must not be taken = لا يجوز اتخاذها — النهي المطلق", xp:25 },
    { id:"mv-t3-7", type:"listen_select", listenSentence:"One might argue that the very concept of objectivity in journalism is inherently problematic", options:["might","must","can","should"], correctAnswer:"might", explanation:"One might argue = قد يرى المرء أن — رأي أكاديمي متحفظ", xp:24 },
    { id:"mv-t3-8", type:"word_order", sentence:"The extent to which these findings can be generalised must be considered with caution", correctAnswer:"The extent to which these findings can be generalised must be considered with caution", explanation:"to which = الذي — ظرف نسبي رسمي، can be generalised = يمكن تعميمها", xp:25 },
    { id:"mv-t3-9", type:"translate", arabic:"ما الذي كان يمكن أن نفعله بشكل مختلف لتفادي هذه الأزمة؟", options:["What could we have done differently to avoid this crisis?","What could we have done different to avoid this crisis?","What must we have done differently to avoid this crisis?","What we could have done differently to avoid this crisis?"], correctAnswer:"What could we have done differently to avoid this crisis?", explanation:"What could we have done? = ما الذي كان بوسعنا فعله؟", xp:25 },
    { id:"mv-t3-10", type:"translate", arabic:"هذه المعضلة الأخلاقية لا يمكن أن تُحلّ بحلول جاهزة — فهي تستلزم حكماً دقيقاً", options:["This ethical dilemma cannot be resolved by ready-made solutions — it requires nuanced judgement","This ethical dilemma must not be resolved by ready-made solutions — it requires nuanced judgement","This ethical dilemma can not be resolved by ready-made solutions — it requires a nuanced judgement","This ethical dilemma cannot resolve by ready-made solutions — it requires nuanced judgement"], correctAnswer:"This ethical dilemma cannot be resolved by ready-made solutions — it requires nuanced judgement", explanation:"cannot be resolved = لا يمكن حله — مبني للمجهول، nuanced = دقيق", xp:25 },
  ],
};

